import { NextResponse } from "next/server";
import axios from "axios";
import * as cheerio from "cheerio";
import { detectComponents } from "@/lib/detector";
import {
  detectComponentsWithLlm,
  detectComponentsHybrid,
} from "@/lib/llm-detector";
import type { ScrapeRequest, ScrapeResponse } from "@/types";

export const runtime = "nodejs";

export async function POST(request: Request) {
  let body: ScrapeRequest;
  try {
    body = (await request.json()) as ScrapeRequest;
  } catch {
    return NextResponse.json<ScrapeResponse>(
      { ok: false, url: "", components: [], error: "invalid_json" },
      { status: 400 },
    );
  }

  const url = body.url?.trim();
  if (!url) {
    return NextResponse.json<ScrapeResponse>(
      { ok: false, url: "", components: [], error: "missing_url" },
      { status: 400 },
    );
  }

  try {
    const res = await axios.get<string>(url, {
      timeout: 20_000,
      responseType: "text",
      headers: {
        "User-Agent":
          "Mozilla/5.0 (compatible; StackshiftBot/0.1; +https://stackshift.dev)",
        Accept: "text/html,application/xhtml+xml",
      },
      maxRedirects: 5,
    });

    const html = res.data;
    const $ = cheerio.load(html);
    const title = $("title").first().text().trim() || undefined;

    const mode = body.detectionMode ?? "heuristic";
    const llm = body.llmConfig;
    const llmReady = !!(llm?.enabled && llm.apiKey.trim());

    console.log(
      `[scrape] url=${url} mode=${mode} llmReady=${llmReady} htmlSize=${html.length}`,
    );

    // ——— LLM-only mode ———
    if (mode === "llm" && llmReady) {
      const result = await detectComponentsWithLlm(html, url, llm!);
      if (result.error && !result.components.length) {
        // All retries exhausted — fall back to heuristic.
        console.warn(`[scrape] LLM failed, falling back to heuristic. Error: ${result.error}`);
        const components = detectComponents(html, url);
        return NextResponse.json<ScrapeResponse>({
          ok: true,
          url,
          title,
          components,
          detectionMethod: "heuristic_fallback",
          llmWarning: result.error,
        });
      }
      console.log(
        `[scrape] LLM succeeded: ${result.components.length} components returned  modelUsed=${result.modelUsed}`,
      );
      const warning = result.notice ?? result.error;
      return NextResponse.json<ScrapeResponse>({
        ok: true,
        url,
        title,
        components: result.components,
        detectionMethod: "llm",
        ...(result.modelUsed ? { modelUsed: result.modelUsed } : {}),
        ...(warning ? { llmWarning: warning } : {}),
      });
    }

    // ——— Hybrid mode ———
    if (mode === "hybrid" && llmReady) {
      const heuristicComponents = detectComponents(html, url);
      console.log(
        `[scrape] Hybrid: heuristic found ${heuristicComponents.length} components, sending to LLM for refinement`,
      );
      const result = await detectComponentsHybrid(
        html,
        url,
        heuristicComponents,
        llm!,
      );
      console.log(
        `[scrape] Hybrid done: ${result.components.length} components, fallback=${result.fallbackUsed}, modelUsed=${result.modelUsed}`,
      );
      const warning = result.notice ?? result.error;
      return NextResponse.json<ScrapeResponse>({
        ok: true,
        url,
        title,
        components: result.components,
        detectionMethod: result.fallbackUsed ? "heuristic_fallback" : "hybrid",
        ...(result.modelUsed ? { modelUsed: result.modelUsed } : {}),
        ...(warning ? { llmWarning: warning } : {}),
      });
    }

    // ——— Default: heuristic ———
    const components = detectComponents(html, url);
    console.log(`[scrape] Heuristic: ${components.length} components`);

    const detectionMethod =
      (mode === "llm" || mode === "hybrid") && !llmReady
        ? "heuristic_fallback"
        : "heuristic";
    const llmWarning =
      (mode === "llm" || mode === "hybrid") && !llmReady
        ? "AI detection requires a configured Gemini API key. Using heuristics instead."
        : undefined;

    return NextResponse.json<ScrapeResponse>({
      ok: true,
      url,
      title,
      components,
      detectionMethod,
      ...(llmWarning ? { llmWarning } : {}),
    });
  } catch (err) {
    const message =
      axios.isAxiosError(err) && err.message
        ? err.message
        : err instanceof Error
          ? err.message
          : "scrape_failed";
    return NextResponse.json<ScrapeResponse>(
      { ok: false, url, components: [], error: message },
      { status: 502 },
    );
  }
}
